// Reads firm details from n8n Variables (project → Variables tab).
// Set: OPS1_SHEET_ID, FIRM_NAME
const SHEET_ID  = $vars.OPS1_SHEET_ID;  // from your compliance sheet URL: .../spreadsheets/d/SHEET_ID/...
const FIRM_NAME = $vars.FIRM_NAME;       // your firm name — used in the email opt-out footer

// Guard: fail loudly if the variable is not set.
if (!SHEET_ID) {
  throw new Error('Bar-Compliance Guardrail is not configured — OPS1_SHEET_ID n8n Variable is not set. Go to project → Variables tab and add it.');
}

const item = $input.first().json;

return [{ json: {
  ...item,
  sheet_id:  SHEET_ID,
  firm_name: FIRM_NAME,
} }];

// Validates required fields from the calling template and normalises them.
const input = $input.first().json;

const required = ['channel', 'recipient', 'message', 'template_id'];
for (const field of required) {
  if (!input[field]) {
    throw new Error(`Bar-Compliance Guardrail: missing required field '${field}'. Check the 'Call Compliance Guardrail' node in ${input.template_id || 'the calling template'}.`);
  }
}

const channel = String(input.channel).trim().toLowerCase();
if (channel !== 'sms' && channel !== 'email') {
  throw new Error(`Bar-Compliance Guardrail: 'channel' must be 'sms' or 'email', got '${channel}'.`);
}

return [{ json: {
  channel,
  recipient:   String(input.recipient).trim(),
  message:     String(input.message).trim(),
  template_id: String(input.template_id).trim(),
  matter_id:   String(input.matter_id || '').trim(),
  firm_name:   String(input.firm_name || '').trim(),
  sheet_id:    String(input.sheet_id).trim(),
  checked_at:  new Date().toISOString(),
} }];

// Checks whether the recipient appears on the opt-out list.
// Uses runOnceForAllItems so it runs safely even when the opt-out sheet is empty (0 rows).
const rows      = $input.all();
const config    = $('Validate And Normalize Compliance Data').first().json;
const recipient = config.recipient.trim().toLowerCase();

let is_opted_out = false;
for (const row of rows) {
  const r     = row.json;
  const phone = (r.phone || '').trim().toLowerCase();
  const email = (r.email || '').trim().toLowerCase();
  if (phone === recipient || email === recipient) {
    is_opted_out = true;
    break;
  }
}

return [{ json: { ...config, is_opted_out } }];

// Pull config from the last node that held the full payload — Log Suppression (Google Sheets)
// may not pass through all fields, so reference the upstream Code node directly.
const config = $('Check Recipient Opt-Out Status').first().json;
return [{ json: {
  ...config,
  approved:           false,
  message_out:        '',
  suppression_reason: 'opted_out',
} }];

const input = $input.first().json;
const { channel, message, firm_name } = input;

let message_out;
if (channel === 'sms') {
  // Append STOP instruction only if not already present.
  const hasStop = /reply stop to opt.?out/i.test(message);
  message_out = hasStop
    ? message
    : `${message}\n\nReply STOP to opt out.`;
} else {
  // Email: append an unsubscribe footer only if not already present.
  const footer = `\n\n---\n${firm_name} | This message is for the intended recipient only. Reply UNSUBSCRIBE to stop receiving messages.`;
  const hasFooter = /reply unsubscribe/i.test(message);
  message_out = hasFooter ? message : `${message}${footer}`;
}

return [{ json: { ...input, message_out } }];

// Pull from Attach Disclaimer (the last Code node before Log to Audit) — ensures all caller
// fields (recipient, matter_id, etc.) are forwarded back to the parent template alongside
// the disclaimer-appended message_out. Log to Audit (Google Sheets) may not pass them through.
const input = $('Append Opt-Out Disclaimer').first().json;
return [{ json: {
  ...input,
  approved:           true,
  suppression_reason: null,
} }];

// Parses the inbound Twilio SMS and classifies it as STOP, UNSTOP, or neither.
// Also reads OPS1_SHEET_ID here so downstream nodes have sheet_id available.

const SHEET_ID = $vars.OPS1_SHEET_ID;
if (!SHEET_ID) {
  throw new Error('Bar-Compliance Guardrail: OPS1_SHEET_ID n8n Variable is not set. Go to project → Variables tab and add it.');
}

const raw  = $input.first().json;
const body = raw.body || raw;

// Twilio POSTs form-encoded; n8n converts to JSON automatically.
const from    = (body.From || '').trim();
const smsBody = (body.Body || '').trim();

// TCPA/Twilio standard STOP and UNSTOP keyword sets — match first word only.
const isStop   = /^(STOP|UNSUBSCRIBE|CANCEL|END|QUIT)\b/i.test(smsBody);
const isUnstop = /^(UNSTOP|START)\b/i.test(smsBody);

return [{ json: {
  from_phone:  from,
  sms_body:    smsBody,
  is_stop:     isStop,
  is_unstop:   isUnstop,
  sheet_id:    SHEET_ID,
  received_at: new Date().toISOString(),
} }];

// Checks whether the inbound phone number is already in the Opt-Outs tab.
// Runs after Read Opt-Outs for STOP — handles 0 rows safely.
const rows  = $input.all();
const parse = $('Parse SMS For STOP Or UNSTOP Keywords').first().json;
const phone = (parse.from_phone || '').trim().toLowerCase();

let already_opted_out = false;
for (const row of rows) {
  const r        = row.json;
  const rowPhone = (r.phone || '').trim().toLowerCase();
  if (rowPhone === phone) {
    already_opted_out = true;
    break;
  }
}

return [{ json: {
  from_phone:        phone,
  sheet_id:          parse.sheet_id,
  received_at:       parse.received_at,
  already_opted_out,
} }];

// Finds the sheet row_number for the UNSTOP sender so the delete node can target it.
// row_number from the Google Sheets read operation is 1-based and includes the header row
// (header = row 1, first data row = row 2). This value maps directly to the delete node's
// 'startIndex' parameter — no offset adjustment needed.
const rows  = $input.all();
const parse = $('Parse SMS For STOP Or UNSTOP Keywords').first().json;
const phone = (parse.from_phone || '').trim().toLowerCase();

let found_row_number = null;
for (const row of rows) {
  const r        = row.json;
  const rowPhone = (r.phone || '').trim().toLowerCase();
  if (rowPhone === phone) {
    found_row_number = r.row_number;
    break;
  }
}

return [{ json: {
  from_phone:       phone,
  sheet_id:         parse.sheet_id,
  found_row_number,
  row_found:        found_row_number !== null,
} }];
